import React, { useCallback, useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';

import {
	ASSET_KEY,
	PARENT_KEY,
	PROJECT_KEY,
	QUERY_KEY,
	WORKSPACE_KEY,
} from './constant/keys';
import { setIds } from './documents/editor/EditorContext';
import decodeParams from './utils/decodeParams';

const HARDCODED_QUERY_PARAM = 'eyJ3IjoicFQ5dkFMeDIzIiwicGEiOiJWNTU2YnA3QjIiLCJhIjoiOTVhMjZhYjktMmU4OC00NGFmLWI2MTUtODVhMDQxNjQ1NzNiIn0=';
const HARDCODED_ACCESS_TOKEN = 'eyJhbGciOiJSUzI1NiIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJEN0t1VlR0eEQ3a2pUbEFkb3Q0WVFMTk90UUNEWWJGZnFEeU9URGJ3VWdjIn0..BG4HN_fyOEHIelElXHAEgC40J-BamQ8SLOfQPt7uxoZSOdygrjMk40SVA029BgzNCX_w272cQAuDvdHC2Nb3lNumx0JX6nUdOp73IpqcLKmutTVHqMTXkHnokSFk6K6zd1kf5yph5ODRXx-ua8tGjMUzJngUdJjN0dH2la_jczFOiRTr-FlgJ-fisjs4IbqPSKBF-OWQJdKKAfWu9mIOV8e8w61fusA2ztTcDErWNkQPzALGoZckT-4Fx1QicoBMmf6hJhJsZug_a83pZx-MC9vq5_zsNSVfsbFWB3IJks90aJw1H0BX_hWTST9GF7SFRdQAN80vt8WsoyIxcuEmUQ';

function AuthRoute({ component: Component }) {
	const [valid, setValid] = useState(false);

	const [searchParams] = useSearchParams();

	const navigate = useNavigate();

	const validateSession = useCallback(() => {
		setValid(false);
		const queryParam = searchParams.get(QUERY_KEY) || HARDCODED_QUERY_PARAM;
		const params = decodeParams(queryParam) || {};

		setIds({
			workspaceId: params[WORKSPACE_KEY],
			projectId: params[PROJECT_KEY],
			parentId: params[PARENT_KEY],
			assetId: params[ASSET_KEY],
		});
		setValid(true);
		window.accessToken = HARDCODED_ACCESS_TOKEN;
	}, [searchParams]);

	useEffect(() => {
		if (!searchParams.get(QUERY_KEY)) {
			// navigate('/redirect-to-home');
			const params = new URLSearchParams(searchParams);
			params.set(QUERY_KEY, HARDCODED_QUERY_PARAM);
			navigate({
				search: params.toString(),
			}, { replace: true });
		}
	}, [navigate, searchParams]);

	useEffect(() => {
		validateSession();
	}, [validateSession]);

	return valid && <Component />;
}

export default AuthRoute;
